  selector: 'hb-field-content, [hb-field-content]',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: { '[class]': 'classes()', '[attr.data-slot]': "'field-content'" },
  exportAs: 'hbFieldContent',
})
