} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { fieldVariants, type HbFieldOrientation } from './field.variants';

@Component({
  selector: 'hb-field, [hb-field]',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'classes()',
    role: 'group',
    '[attr.data-invalid]': "hbInvalid() ? 'true' : null",
    '[attr.data-slot]': "'field'",
  },
  exportAs: 'hbField',
})
export class HbFieldComponent {
  readonly hbOrientation = input<HbFieldOrientation>('vertical');
  readonly hbInvalid = input(false, { transform: booleanAttribute });
  readonly class = input<ClassValue>('');
  protected readonly classes = computed(() =>
    cn(fieldVariants({ orientation: this.hbOrientation() }), this.class()),
  );
}

import { HbFieldComponent } from './field.component';
import { HbFieldContentComponent } from './field-content.component';
import { HbFieldDescriptionComponent } from './field-description.component';
import { HbFieldErrorComponent } from './field-error.component';
import { HbFieldGroupComponent } from './field-group.component';
import { HbFieldLabelComponent } from './field-label.component';
import { HbFieldLegendComponent } from './field-legend.component';
import { HbFieldSeparatorComponent } from './field-separator.component';
import { HbFieldSetComponent } from './field-set.component';
import { HbFieldTitleComponent } from './field-title.component';

export const HbFieldImports = [
  HbFieldComponent,
  HbFieldLabelComponent,
  HbFieldTitleComponent,
  HbFieldDescriptionComponent,
  HbFieldErrorComponent,
  HbFieldContentComponent,
  HbFieldGroupComponent,
  HbFieldSetComponent,
  HbFieldLegendComponent,
  HbFieldSeparatorComponent,
] as const;

import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '{{alias}}/utils';

export const fieldVariants = cva('group/field flex w-full gap-2 data-[invalid=true]:text-destructive', {
  variants: {
    orientation: {
      vertical: 'flex-col',
      horizontal:
        'flex-row items-center [&>[data-slot=field-label]]:flex-auto has-[>[data-slot=field-content]]:items-start has-[>[data-slot=field-content]]:[&>[data-slot=checkbox]]:mt-0.5',
      responsive:
        'flex-col @md/field-group:flex-row @md/field-group:items-center @md/field-group:[&>[data-slot=field-label]]:flex-auto @md/field-group:has-[>[data-slot=field-content]]:items-start',
    },
  },
  defaultVariants: { orientation: 'vertical' },
});

export const fieldLabelVariants = cva(
  cn(
    'flex select-none items-center gap-1 text-sm font-medium leading-none text-foreground',
    'group-data-[invalid=true]/field:text-destructive peer-disabled:opacity-50',
  ),
);

export const fieldTitleVariants = cva('flex items-center gap-1 text-sm font-medium leading-none');
export const fieldDescriptionVariants = cva('text-sm leading-normal text-muted-foreground');
export const fieldErrorVariants = cva('text-sm font-medium text-destructive');
export const fieldContentVariants = cva('flex flex-1 flex-col gap-1.5');

export const fieldGroupVariants = cva('@container/field-group flex w-full flex-col gap-6', {
  variants: {
    columns: {
      1: '',
      2: 'grid grid-cols-1 gap-4 @md/field-group:grid-cols-2',
      3: 'grid grid-cols-1 gap-4 @md/field-group:grid-cols-3',
    },
  },
  defaultVariants: { columns: 1 },
});

export const fieldSetVariants = cva('flex flex-col gap-4');
export const fieldLegendVariants = cva('mb-1 font-medium', {
  variants: { variant: { legend: 'text-base', label: 'text-sm' } },
  defaultVariants: { variant: 'legend' },
});
export const fieldSeparatorVariants = cva('my-1 h-px w-full bg-border');

export type HbFieldOrientation = NonNullable<VariantProps<typeof fieldVariants>['orientation']>;
export type HbFieldColumns = NonNullable<VariantProps<typeof fieldGroupVariants>['columns']>;
export type HbFieldLegendVariant = NonNullable<VariantProps<typeof fieldLegendVariants>['variant']>;

export * from './field.component';
export * from './field-label.component';
export * from './field-title.component';
export * from './field-description.component';
export * from './field-error.component';
export * from './field-content.component';
export * from './field-group.component';
export * from './field-set.component';
export * from './field-legend.component';
export * from './field-separator.component';
export * from './field.variants';
export * from './field.imports';

